def _tenant_dir(tenant_id: str) -> str:
    safe = tenant_id.strip().replace("..", "").replace("/", "_").replace("\\", "_")
    if not safe:
        raise HTTPException(status_code=400, detail="Invalid tenant_id")
    d = os.path.join(BASE_DIR, safe)
    os.makedirs(d, exist_ok=True)
    return d


def _model_path(tenant_id: str, model_id: str) -> str:
    safe_id = model_id.strip().replace("..", "").replace("/", "_").replace("\\", "_")
    if not safe_id:
        raise HTTPException(status_code=400, detail="Invalid model_id")
    return os.path.join(_tenant_dir(tenant_id), f"{safe_id}.pkl")


def _cache_key(tenant_id: str, model_id: str) -> str:
    return f"{tenant_id}::{model_id}"


def _evict_expired_cache() -> None:
    with _store_lock:
        now = _now()
