def _invoke_inference(model: Any, req: PredictRequest) -> Any:
    kwargs = req.kwargs or {}
    if req.method:
        if not hasattr(model, req.method):
            raise HTTPException(status_code=400, detail=f"Model has no method '{req.method}'")
        fn = getattr(model, req.method)
    else:
        if hasattr(model, "predict"):
            fn = getattr(model, "predict")
        elif callable(model):
            fn = model
        else:
            raise HTTPException(status_code=400, detail="Model is not callable and has no 'predict' method")
    try:
        return fn(req.inputs, **kwargs)
    except TypeError:
        try:
            return fn(req.inputs)
        except Exception as e:
            raise HTTPException(status_code=500, detail=f"Inference failed: {type(e).__name__}: {e}")
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Inference failed: {type(e).__name__}: {e}")


