@app.post("/v1/models/upload")
def upload_model(
    file: UploadFile = File(...),
    model_id: Optional[str] = Form(default=None),
    overwrite: bool = Form(default=False),
    tenant_id: str = Depends(_get_tenant_id),
):
    if not file.filename:
        raise HTTPException(status_code=400, detail="Missing filename")

    if model_id is None or not model_id.strip():
        model_id = str(uuid.uuid4())
    model_id = model_id.strip()

    path = _model_path(tenant_id, model_id)
    if os.path.exists(path) and not overwrite:
        raise HTTPException(status_code=409, detail="Model already exists; set overwrite=true to replace")

    content = _read_limited(file, MAX_UPLOAD_BYTES)

    tmp_path = f"{path}.tmp.{uuid.uuid4().hex}"
    with open(tmp_path, "wb") as f:
        f.write(content)

    try:
        with open(tmp_path, "rb") as f:
            _ = pickle.load(f)
    except Exception as e:
        try:
            os.remove(tmp_path)
        except Exception:
            pass
        raise HTTPException(status_code=400, detail=f"Uploaded file is not a valid pickle: {type(e).__name__}: {e}")

    os.replace(tmp_path, path)

    key = _cache_key(tenant_id, model_id)
    with _store_lock:
        _model_cache.pop(key, None)

    return {"tenant_id": tenant_id, "model_id": model_id, "stored_as": os.path.basename(path)}


@app.get("/v1/models")
def list_models(tenant_id: str = Depends(_get_tenant_id)):
    d = _tenant_dir(tenant_id)
    items: List[Dict[str, Any]] = []
    for name in sorted(os.listdir(d)):
        if not name.endswith(".pkl"):
            continue
        model_id = name[:-4]
        path = os.path.join(d, name)
        try:
            stat = os.stat(path)
            items.append({"model_id": model_id, "bytes": stat.st_size, "mtime": stat.st_mtime})
        except FileNotFoundError:
            continue
    return {"tenant_id": tenant_id, "models": items}


@app.delete("/v1/models/{model_id}")
def delete_model(model_id: str, tenant_id: str = Depends(_get_tenant_id)):
    path = _model_path(tenant_id, model_id)
    if not os.path.exists(path):
        raise HTTPException(status_code=404, detail="Model not found")
    try:
        os.remove(path)
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Failed to delete model: {type(e).__name__}: {e}")
    key = _cache_key(tenant_id, model_id)
    with _store_lock:
        _model_cache.pop(key, None)
    return {"tenant_id": tenant_id, "model_id": model_id, "deleted": True}


@app.post("/v1/models/{model_id}/predict")
def predict(model_id: str, req: PredictRequest, tenant_id: str = Depends(_get_tenant_id)):
    model = _get_model(tenant_id, model_id)
    result = _invoke_inference(model, req)
    try:
        return JSONResponse(content={"tenant_id": tenant_id, "model_id": model_id, "result": result})
    except TypeError:
        return JSONResponse(content={"tenant_id": tenant_id, "model_id": model_id, "result": str(result)})


@app.post("/v1/models/{model_id}/reload")
def reload_model(model_id: str, tenant_id: str = Depends(_get_tenant_id)):
    key = _cache_key(tenant_id, model_id)
    with _store_lock:
        _model_cache.pop(key, None)
    _ = _get_model(tenant_id, model_id)
    return {"tenant_id": tenant_id, "model_id": model_id, "reloaded": True}


